import {
  computed,
  inject,
  Injectable,
  signal,
  WritableSignal,
} from '@angular/core';
import {
  AccountsService,
  AuthService,
  UserProfileResponse,
  UserRoleResponse,
} from '../../api';
import { Router } from '@angular/router';
import { AuthTokenManagerService } from './auth-token-manager.service';
import { AdminStateService } from '../../features/administration/services/admin-state.service';
import { firstValueFrom } from 'rxjs';
import { isEmpty, isNullOrUndefined } from '../../shared/utils';
import { DEFAULT_SYSTEM_ID, SUPER_ADMIN_ROLE_ID } from '../models';

@Injectable({
  providedIn: 'root',
})
export class AuthDataService {
  private readonly userProfileSignal = signal<UserProfileResponse | null>(null);
  private readonly userPermissionsSignal = signal<string[]>([]);
  private readonly router = inject(Router);
  private readonly authService = inject(AuthService);
  private readonly authTokensService = inject(AuthTokenManagerService);
  private readonly adminState = inject(AdminStateService);
  private readonly accountsService = inject(AccountsService);
  flags = {
    otpTestingEnabled: () =>
      this.getUserProfile()?.owner.type === 'system' ||
      this.getUserProfile()?.emailAddress?.endsWith('keytelematics.com'),
    labelsEnabled: () => true,
    tripLimitsEnabled: () => true,
    assetPerformanceEnabled: () =>
      this.getUserProfile()?.owner?.type === 'system' ||
      this.getUserProfile()?.emailAddress?.endsWith('keytelematics.com'),
    deviceHealthEnabled: () =>
      this.getUserProfile()?.owner?.type === 'system' ||
      this.getUserProfile()?.emailAddress?.endsWith('keytelematics.com'),
  };

  /**
   * Computed signal for accessing the user profile
   */
  readonly profile = computed(() => this.userProfileSignal());

  /**
   * Returns the writable signal for the user profile
   */
  getUserProfileSignal(): WritableSignal<UserProfileResponse | null> {
    return this.userProfileSignal;
  }

  /**
   * Returns the current user profile value
   */
  getUserProfile(): UserProfileResponse | null {
    return this.userProfileSignal();
  }

  /**
   * Updates the user profile, merging with existing data if present
   * Also extracts and sets user permissions.
   * @param userProfile - Partial user profile data to update
   */
  async setUserProfile(
    userProfile: Partial<UserProfileResponse>,
  ): Promise<void> {
    const currentProfile = this.userProfileSignal();
    let updatedProfile: UserProfileResponse;

    if (!currentProfile) {
      updatedProfile = userProfile as UserProfileResponse;
    } else {
      updatedProfile = { ...currentProfile, ...userProfile };
    }
    this.userProfileSignal.set(updatedProfile);

    // Extract permissions from all roles
    await this.extractAndSetAllPermissions(updatedProfile.roles || []);
  }

  /**
   * Extracts permissions from all user roles and updates the permissions signal.
   * @param roles - Array of user roles
   */
  private async extractAndSetAllPermissions(
    roles: UserProfileResponse['roles'],
  ): Promise<void> {
    if (!roles || roles.length === 0) {
      this.userPermissionsSignal.set([]);
      return;
    }

    const allPermissions: string[] = [];

    for (const role of roles) {
      const permissions = await this.extractPermissionsFromRole(role.id);
      allPermissions.push(...permissions);
    }

    // Remove duplicates and set all permissions
    this.userPermissionsSignal.set([...new Set(allPermissions)]);
  }

  /**
   * Extracts permissions from a single role
   * @param roleId - The role ID
   * @returns Promise<string[]> - Array of permissions for this role
   */
  private async extractPermissionsFromRole(roleId: string): Promise<string[]> {
    if (isNullOrUndefined(roleId)) {
      console.warn('Cannot extract permissions: Role ID is missing.');
      return [];
    }

    if (roleId === DEFAULT_SYSTEM_ID) {
      return ['system:all'];
    }

    try {
      const userRole: UserRoleResponse = await firstValueFrom(
        this.accountsService.getUserRole(roleId),
      );

      if (isNullOrUndefined(userRole) || !userRole.legacyRights) {
        if (isNullOrUndefined(userRole)) {
          console.warn('UserRoleResponse is null or undefined.');
        } else {
          console.warn('legacyRights are missing in UserRoleResponse.');
        }
        return [];
      }

      const permissions: string[] = [];
      const legacyRights = userRole.legacyRights;

      for (const feature in legacyRights) {
        if (Object.hasOwn(legacyRights, feature)) {
          const actions = legacyRights[feature as keyof typeof legacyRights];
          if (Array.isArray(actions)) {
            actions.forEach((action: string) => {
              permissions.push(`${feature}:${action}`);
            });
          }
        }
      }

      return permissions;
    } catch (error) {
      console.error(
        'Error fetching or processing user role for permissions:',
        error,
      );
      return [];
    }
  }
  /**
   * Checks if the current user has a specific permission.
   * @param permission - The permission string to check for.
   */
  hasPermission(permission: string): boolean {
    return (
      this.userPermissionsSignal().includes(permission) ||
      this.userPermissionsSignal().includes('system:all')
    );
  }

  /**
   * Checks if the current user has ALL of the specified permissions.
   * @param permissions - An array of permission strings to check for.
   */
  hasAllPermissions(permissions: string[]): boolean {
    if (isEmpty(permissions) || permissions.length === 0) {
      return true; // No permissions required
    }
    const userPerms = this.userPermissionsSignal();
    return (
      permissions.every((p) => userPerms.includes(p)) ||
      userPerms.includes('system:all')
    );
  }

  /**
   * Checks if the current user has ANY of the specified permissions.
   * @param permissions - An array of permission strings to check for.
   */
  hasAnyPermission(permissions: string[]): boolean {
    if (isEmpty(permissions) || permissions.length === 0) {
      return true; // No permissions required
    }
    const userPerms = this.userPermissionsSignal();
    return (
      permissions.some((p) => userPerms.includes(p)) ||
      userPerms.includes('system:all')
    );
  }

  /**
   * Clears the user profile data and permissions
   */
  clearUserProfile(): void {
    this.userProfileSignal.set(null);
    this.userPermissionsSignal.set([]);
  }

  logout() {
    this.authService.signOut({}).subscribe({
      next: () => {
        this.authTokensService.clearTokens();
        this.adminState.clearAllState();
        this.clearUserProfile(); // Ensure permissions are cleared
        this.router.navigate(['/auth']).catch(() => {});
      },
      error: () => {
        // Even if signOut fails, we should still clear local data and redirect
        this.forceLogout();
      },
    });
  }

  forceLogout() {
    this.authTokensService.clearTokens();
    this.adminState.clearAllState();
    this.clearUserProfile(); // Ensure permissions are cleared
    this.router.navigate(['/auth']).catch(() => {});
  }

  /**
   * Checks if the current user is a Super Admin.
   * Super Admins can view and manage the top level above distributors.
   */
  isSuperAdmin(): boolean {
    const userProfile = this.userProfileSignal();
    if (!userProfile?.roles) return false;

    return userProfile.roles.some(
      (role) =>
        role.id === DEFAULT_SYSTEM_ID ||
        role.id === SUPER_ADMIN_ROLE_ID ||
        (role.name?.toLowerCase().includes('super admin') ?? false),
    );
  }
}
